import React, { useCallback, useMemo, useState } from 'react';
import { LinErpListFilterBar, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatDate, formatNumber, formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { AgedStockRow } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-bao-cao-ton-kho-cu';
const PAGE_ID = 'baocao-ton-kho-cu';
const AGE_OPTIONS = [
  { value: '30', label: '30+ ngày' },
  { value: '60', label: '60+ ngày' },
  { value: '90', label: '90+ ngày' },
  { value: '180', label: '180+ ngày' },
  { value: '365', label: '1 năm+' },
];

const BaoCaoTonKhoCuPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [minDays, setMinDays] = useState('90');
  const [rows, setRows] = useState<AgedStockRow[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getAgedStock({ minDays: Number(minDays) })
      .then(setRows)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [minDays, dispatch]);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        onDateChange={() => {}}
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
        leading={(
          <div data-testid={`${TEST_ID}-field-age`}>
            <Select
              label="Tuổi tồn tối thiểu"
              value={minDays}
              onChange={e => setMinDays(e.target.value)}
              options={AGE_OPTIONS}
              size="small"
            />
          </div>
        )}
      />
    ),
    [minDays, handleLoad, loading],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Tồn kho lâu ngày"
      titleIconClass="fas fa-hourglass-half"
      loading={loading}
      hasData={rows.length > 0}
      filters={listFilters}
      onLoad={handleLoad}
      exportPath="/wms/reports/aged-stock/export-excel"
      exportParams={{ minDays }}
      exportFilename={`TonKhoCu-${minDays}ngay.xlsx`}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th>Mã</th>
            <th>Tên</th>
            <th>Kho</th>
            <th className={reportStyles.colRight}>SL</th>
            <th className={reportStyles.colRight}>GT</th>
            <th>Ngày ĐC</th>
            <th className={reportStyles.colRight}>Tuổi (ngày)</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i} className={r.ageDays >= 180 ? reportStyles.rowDanger : undefined}>
              <td>{r.productCode}</td>
              <td>{r.productName}</td>
              <td>{r.warehouseName}</td>
              <td className={reportStyles.colRight}>{formatNumber(r.qty)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.totalValue)}</td>
              <td>{formatDate(r.lastMovementDate)}</td>
              <td className={reportStyles.colRight}>{r.ageDays}</td>
            </tr>
          ))}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default BaoCaoTonKhoCuPage;
